import {
  DURATION,
  EASING,
  SPRING_CONFIGS,
  TRANSITIONS,
  cubicBezierCSS,
} from './tokens.js';
import { springToLinear } from './spring-resolver.js';

export default {
  title: 'Motion/Platform',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'Platform output: how each token resolves across CSS, SwiftUI, and Compose. ' +
          'Spring configs use springToLinear() for CSS; SwiftUI and Compose receive ' +
          'approximated native equivalents.',
      },
    },
  },
};

// ---------------------------------------------------------------------------
// Platform resolver
// ---------------------------------------------------------------------------

/**
 * Returns platform-specific output for a given token category and value.
 *
 * @param {'duration'|'easing'|'spring'|'transition'} category
 * @param {*} value — the token value
 * @param {object} [aux] — additional info (e.g. duration for transition)
 * @returns {{ css: string, swiftui: string, compose: string }}
 */
function platformResolve(category, value, aux = {}) {
  switch (category) {
    case 'duration': {
      const ms = parseInt(value, 10);
      const s  = (ms / 1000).toFixed(3).replace(/\.?0+$/, '');
      return {
        css:     `${ms}ms`,
        swiftui: `${s}`,
        compose: `${ms}`,
      };
    }

    case 'easing': {
      const [x1, y1, x2, y2] = value;
      const composeLabel = easingToComposeLabel(x1, y1, x2, y2);
      return {
        css:     `cubic-bezier(${x1}, ${y1}, ${x2}, ${y2})`,
        swiftui: `.timingCurve(${x1}, ${y1}, ${x2}, ${y2}, duration: ...)`,
        compose: composeLabel,
      };
    }

    case 'spring': {
      const { stiffness, damping, mass } = value;
      const { css, duration, dampingRatio } = springToLinear(stiffness, damping, mass);
      // Approximate SwiftUI response from stiffness/mass: response ≈ 2π/ω₀
      const omega0   = Math.sqrt(stiffness / mass);
      const response = +((2 * Math.PI) / omega0).toFixed(2);
      const df       = +dampingRatio.toFixed(2);
      // Compose: spring(stiffness, dampingRatio) — damping ratio in [0,1] maps to dampingRatio param
      const composeDamp = +(dampingRatio).toFixed(3);
      return {
        css:     css,
        swiftui: `.spring(response: ${response}, dampingFraction: ${df})`,
        compose: `spring(stiffness=${stiffness}f, dampingRatio=${composeDamp}f)`,
        duration,
      };
    }

    case 'transition': {
      const { duration, easing, delay } = value;
      const ms = parseInt(duration, 10);
      const s  = (ms / 1000).toFixed(3).replace(/\.?0+$/, '');
      const [x1, y1, x2, y2] = easing;
      const delayMs = parseInt(delay || '0', 10);
      const composeLabel = easingToComposeLabel(x1, y1, x2, y2);
      return {
        css:     `${ms}ms cubic-bezier(${x1}, ${y1}, ${x2}, ${y2}) ${delayMs}ms`,
        swiftui: `.animation(.timingCurve(${x1}, ${y1}, ${x2}, ${y2}, duration: ${s}))`,
        compose: `tween(durationMillis=${ms}, easing=${composeLabel})`,
      };
    }

    default:
      return { css: '—', swiftui: '—', compose: '—' };
  }
}

// Approximate a cubic-bezier to a named Compose easing constant
function easingToComposeLabel(x1, y1, x2, y2) {
  if (x1 === 0 && y1 === 0 && x2 === 1 && y2 === 1) return 'LinearEasing';
  if (x1 === 0 && y1 === 0 && x2 === 0.2 && y2 === 1) return 'FastOutLinearInEasing';
  if (x1 === 0.4 && y1 === 0 && x2 === 1 && y2 === 1) return 'LinearOutSlowInEasing';
  if (x1 === 0.4 && y1 === 0 && x2 === 0.2 && y2 === 1) return 'FastOutSlowInEasing';
  if (x1 === 0.2 && y1 === 0 && x2 === 0 && y2 === 1) return 'EmphasizedEasing';
  return `PathInterpolator(${x1}f, ${y1}f, ${x2}f, ${y2}f)`;
}

// ---------------------------------------------------------------------------
// Build token rows for the table
// ---------------------------------------------------------------------------
function buildAllTokenRows() {
  const rows = [];

  // Duration primitives
  Object.entries(DURATION).forEach(([key, val]) => {
    const p = platformResolve('duration', val);
    rows.push({ category: 'Duration', name: `duration.${key}`, css: p.css, swiftui: p.swiftui, compose: p.compose });
  });

  // Easing primitives
  Object.entries(EASING).forEach(([key, val]) => {
    const p = platformResolve('easing', val);
    rows.push({ category: 'Easing', name: `easing.${key}`, css: p.css, swiftui: p.swiftui, compose: p.compose });
  });

  // Spring configs
  Object.entries(SPRING_CONFIGS).forEach(([key, val]) => {
    const p = platformResolve('spring', val);
    const shortCss = p.css.length > 60 ? p.css.slice(0, 60) + '...' : p.css;
    rows.push({ category: 'Spring', name: `spring.config.${key}`, css: shortCss, swiftui: p.swiftui, compose: p.compose, fullCss: p.css });
  });

  // Composite transitions
  Object.entries(TRANSITIONS).forEach(([key, val]) => {
    const p = platformResolve('transition', val);
    rows.push({ category: 'Transition', name: `motion.transition.${key}`, css: p.css, swiftui: p.swiftui, compose: p.compose });
  });

  return rows;
}

// ---------------------------------------------------------------------------
// Dropdown token list for the inspector
// ---------------------------------------------------------------------------
function buildInspectorTokenList() {
  const list = [];

  Object.entries(DURATION).forEach(([k, v]) => {
    list.push({ label: `duration.${k}`, category: 'duration', value: v });
  });
  Object.entries(EASING).forEach(([k, v]) => {
    list.push({ label: `easing.${k}`, category: 'easing', value: v });
  });
  Object.entries(SPRING_CONFIGS).forEach(([k, v]) => {
    list.push({ label: `spring.config.${k}`, category: 'spring', value: v });
  });
  Object.entries(TRANSITIONS).forEach(([k, v]) => {
    list.push({ label: `motion.transition.${k}`, category: 'transition', value: v });
  });

  return list;
}

