// ---------------------------------------------------------------------------
// Story 1 — PlatformTokenTable
// ---------------------------------------------------------------------------
export const PlatformTokenTable = {
  name: 'Platform token table',
  render: () => {
    const rows = buildAllTokenRows();

    // Group by category
    const categories = [...new Set(rows.map(r => r.category))];
    const tableRows = categories.flatMap(cat => {
      const catRows = rows.filter(r => r.category === cat);
      return [
        `<tr class="category-header"><td colspan="4">${cat}</td></tr>`,
        ...catRows.map(r => `
          <tr>
            <td class="name-cell">${r.name}</td>
            <td>${r.css}</td>
            <td>${r.swiftui}</td>
            <td>${r.compose}</td>
          </tr>
        `),
      ];
    });

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Platform</div>
        <div class="page-subtitle">Platform token table</div>
        <div class="page-description">
          Resolved output for every token across CSS, SwiftUI, and Compose.
          Spring config CSS values show the first 60 characters of the <code style="font-family:monospace;background:#eee;padding:1px 4px;border-radius:3px;">linear()</code> string.
          Use the Platform inspector story to view the full value.
        </div>
        <div style="overflow-x: auto;">
          <table class="token-table">
            <thead>
              <tr>
                <th>Token</th>
                <th>CSS</th>
                <th>SwiftUI</th>
                <th>Compose</th>
              </tr>
            </thead>
            <tbody>
              ${tableRows.join('')}
            </tbody>
          </table>
        </div>
      </div>
    `;

    return el;
  },
};

